 28	#define MAX_NUM_RIC_REQ_ID 64
 29	
 30	static pthread_mutex_t rc_mutex = PTHREAD_MUTEX_INITIALIZER;
 31	
 32	int cmp_ric_req_id(struct ric_req_id_s *c1, struct ric_req_id_s *c2)
 33	{
 34	  if (c1->ric_req_id < c2->ric_req_id)
 35	    return -1;
 36	
 37	  if (c1->ric_req_id > c2->ric_req_id)
 38	    return 1;
 39	
 40	  return 0;
 41	}
 42	
 43	RB_GENERATE(ric_id_2_param_id_trees, ric_req_id_s, entries, cmp_ric_req_id);
 44	
 45	void init_rc_subs_data(rc_subs_data_t* rc_subs_data)
 46	{
 47	  pthread_mutex_lock(&rc_mutex);
 48	 
 49	  // Initialize hash table
 50	  DevAssert(rc_subs_data->htable == NULL);
 51	 
 52	  // Initialize RB trees
 53	  // 1 RB tree = 1 ran_param_id => many ric_req_id(s)
 54	  for (size_t i = 0; i < END_E2SM_RC_RAN_PARAM_ID; i++) {
 55	    RB_INIT(&rc_subs_data->rb[i]);
 56	  }
 57	
 58	   rc_subs_data->htable = hashtable_create(MAX_NUM_RIC_REQ_ID, NULL, free);
 59	  assert(rc_subs_data->htable != NULL && "Memory exhausted");
 60	  pthread_mutex_unlock(&rc_mutex);
 61	}
 62	
 63	void insert_rc_subs_data(rc_subs_data_t* rc_subs_data, uint32_t ric_req_id, arr_ran_param_id_t* arr_ran_param_id)
 64	{
 65	  pthread_mutex_lock(&rc_mutex);
 66	
 67	  // Insert in hash table
 68	  DevAssert(rc_subs_data->htable != NULL);
 69	  uint64_t key = ric_req_id;
 70	  // Check if the subscription already exists
 71	  AssertFatal(hashtable_is_key_exists(rc_subs_data->htable, key) == HASH_TABLE_KEY_NOT_EXISTS, "RIC req ID %d already subscribed", ric_req_id);
 72	  arr_ran_param_id_t* data = malloc(sizeof(*data));
 73	  assert(data != NULL);
 74	  *data = *arr_ran_param_id;
 75	  hashtable_rc_t ret = hashtable_insert(rc_subs_data->htable, key, data);
 76	  assert(ret == HASH_TABLE_OK  && "Hash table not ok");
 77	
 78	  // Insert in RB trees
 79	  // 1 RB tree = 1 ran_param_id => many ric_req_id(s)
 80	  const size_t sz = arr_ran_param_id->len;
 81	  rb_ric_req_id_t *node = calloc(1, sizeof(*node));
 82	  assert(node != NULL);
 83	  node->ric_req_id = ric_req_id;
 84	  for (size_t i = 0; i < sz; i++) {
 85	    RB_INSERT(ric_id_2_param_id_trees, &rc_subs_data->rb[arr_ran_param_id->ran_param_id[i]], node);
 86	  }
 87	
 88	  pthread_mutex_unlock(&rc_mutex);
 89	}
 90	
 91	void remove_rc_subs_data(rc_subs_data_t* rc_subs_data, uint32_t ric_req_id)
 92	{
 93	  pthread_mutex_lock(&rc_mutex);
 94	  DevAssert(rc_subs_data->htable != NULL);
 95	
 96	  uint64_t key = ric_req_id;
 97	  // Get the array of ran_param_id(s)
 98	  void *data = NULL;
 99	  hashtable_rc_t ret = hashtable_get(rc_subs_data->htable, key, &data);
100	  AssertFatal(ret == HASH_TABLE_OK && data != NULL, "element for ue_id %d not found\n", ric_req_id);
101	  arr_ran_param_id_t arr_ran_param_id = *(arr_ran_param_id_t *)data;
102	  // Remove ric_req_id with its ran_param_id(s) from hash table
103	  ret = hashtable_remove(rc_subs_data->htable, key);
104	  
105	  // Remove ric_req_id from each ran_param_id tree where subscribed
106	  rb_ric_req_id_t *node = calloc(1, sizeof(*node));
107	  assert(node != NULL);
108	  node->ric_req_id = ric_req_id;
109	  for (size_t i = 0; i < arr_ran_param_id.len; i++) {
110	    RB_REMOVE(ric_id_2_param_id_trees, &rc_subs_data->rb[arr_ran_param_id.ran_param_id[i]], node);
111	  }
112	
113	  pthread_mutex_unlock(&rc_mutex);
114	}

